import React from 'react';
import './BasicPage.css';

const BasicPage = () => {
  return (
    <div className="basic-page">
      <div className="container">
        <header>
          <h1>This is the heading</h1>
        </header>
        <main>
          <p>This is some text</p>
          <ol>
            <li><b>Point</b> A</li>
            <li><b>Point</b> B</li>
          </ol>
          <p>
            Go to: <a target="_blank" href="https://tagesschau.de" rel="noopener noreferrer">Link to Tagesschau</a>
          </p>
          <img src="https://edgar-seemann.de/web/res/images/study.svg" alt="Study Illustration" />
        </main>
      </div>
    </div>
  );
};

export default BasicPage;
